    ('bidriware','Karnataka Crafts Sales Cell','State Handicrafts Marketing','government','Official Bidri sales facilitation','https://karnataka.gov.in','Bengaluru',TRUE,1),
    ('bidriware','Bidri Artisan Guild','Bidar Inlay Cooperative','cooperative','Guild office support','https://www.craftscouncilofindia.org','Bidar',FALSE,2),
    ('jaipur-blue-pottery','Rajasthan Craft Hub','Rajasthan Small Industries Corp','government','Blue pottery support desk','https://www.rsic.rajasthan.gov.in','Jaipur',TRUE,1),
