    ('pattachitra-raghurajpur','Raghurajpur Artist Collective','Village Artisan Cooperative','cooperative','Artist village info desk','https://odishatourism.gov.in','Raghurajpur',FALSE,2),
    ('dhokra-bastar','Chhattisgarh Craft Board','State Tribal Craft Facilitation','government','Tribal craft support helpline','https://www.tribal.cg.gov.in','Raipur',TRUE,1),
    ('dhokra-bastar','Bastar Dhokra Collective','Artisan Cooperative Society','cooperative','Workshop cluster office','https://www.tribesindia.com','Kondagaon',FALSE,2),
    ('saharanpur-wood-carving','UP Handicrafts Desk','UP Export & Crafts Facilitation','government','Official cluster guidance','https://www.upgov.in','Saharanpur',TRUE,1),
    ('moradabad-brassware','Moradabad Metal Craft Cell','State-supported brass cluster office','government','Quality and market support line','https://www.epch.in','Moradabad',TRUE,1),
    ('kashmir-paper-mache','J&K Arts Cell','J&K Handicrafts Department','government','Certified artisan registry support','https://www.jkhandicrafts.com','Srinagar',TRUE,1),
    ('kashmir-walnut-carving','Kashmir Walnut Collective','Registered Artisan Cooperative','cooperative','Workshop and purchase support','https://www.jktdc.co.in','Srinagar',FALSE,2),
